#include <stdio.h>
#include <stdlib.h>

struct Osoba {
    char ime[20];
    int godine;
};

void zapisi(struct Osoba* imenik, int broj_osoba) {
    FILE* dat = fopen("baza.dat", "wb");
    if (dat == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        exit(1);
    }

    int zapisano = fwrite(imenik, sizeof(struct Osoba), broj_osoba, dat);
    if (ferror(dat)) {
        printf("Greska prilikom pisanja datoteke.\n");
        printf("Zapisano je samo %d osoba\n", zapisano);
    }

    fclose(dat);
}

int main() {
    struct Osoba imenik[3] = {
        {"Ana", 21},
        {"Marko", 25},
        {"Sara", 30}
    };

    int broj_osoba = 3;

    zapisi(imenik, broj_osoba);

    printf("Binarna datoteka baza.dat je uspjesno kreirana.\n");

    return 0;
}
